56	
57	interface EvidenceNodeData extends Record<string, unknown> {
58	  evidence: EvidenceItem;
59	  onUpdateEvidence: (id: string, updates: Partial<EvidenceItem>) => void;
60	  onDeleteEvidence: (id: string) => void;
61	}
62	
63	const evidenceTypeOptions = [
64	  {
65	    value: 'Experiment',
66	    icon: FlaskConical,
67	    color: 'bg-blue-50 text-blue-700',
68	  },
69	  { value: 'Analysis', icon: FileText, color: 'bg-green-50 text-green-700' },
70	  { value: 'Notebook', icon: BookOpen, color: 'bg-purple-50 text-purple-700' },
71	  {
72	    value: 'External Research',
73	    icon: Globe,
74	    color: 'bg-orange-50 text-orange-700',
75	  },
76	  { value: 'User Interview', icon: Users, color: 'bg-pink-50 text-pink-700' },
77	];
78	
79	// Debounce function for auto-save
80	function debounce<T extends (...args: any[]) => any>(
81	  func: T,
82	  wait: number
83	): (...args: Parameters<T>) => void {
84	  let timeout: NodeJS.Timeout;
85	  return (...args: Parameters<T>) => {
86	    clearTimeout(timeout);
87	    timeout = setTimeout(() => func(...args), wait);
88	  };
89	}
90	
91	type EvidenceFlowNode = Node<EvidenceNodeData, 'evidence'>;
92	
93	export default function EvidenceNode({ data }: NodeProps<EvidenceFlowNode>) {
94	  if (!data) return null;
95	  const { evidence, onUpdateEvidence, onDeleteEvidence } = data;
96	  const { addComment } = useEvidenceStore();
97	
98	  const editorRef = useRef<EditorJS | null>(null);
99	  const editorContainerRef = useRef<HTMLDivElement>(null);
100	  const [isExpanded, setIsExpanded] = useState(evidence.isExpanded || false);
101	  const [isEditing, setIsEditing] = useState(false);
102	  const [isCommentDialogOpen, setIsCommentDialogOpen] = useState(false);
103	  const [isFullscreen, setIsFullscreen] = useState(false);
104	  const [isAutoSaving, setIsAutoSaving] = useState(false);
105	  const [lastSaved, setLastSaved] = useState<Date | null>(null);
106	  const [isLoading, setIsLoading] = useState(false);
107	  const [newComment, setNewComment] = useState('');
108	  const [editForm, setEditForm] = useState<Partial<EvidenceItem>>({
109	    title: evidence.title,
110	    type: evidence.type,
111	    date: evidence.date,
112	    owner: evidence.owner,
113	    summary: evidence.summary,
114	    hypothesis: evidence.hypothesis,
115	    impactOnConfidence: evidence.impactOnConfidence,
116	    link: evidence.link,
117	    tags: evidence.tags || [],
118	  });
119	
120	  const getTypeIcon = (type: string) => {
121	    const option = evidenceTypeOptions.find((opt) => opt.value === type);
122	    return option ? option.icon : FileText;
123	  };
124	
125	  const getTypeColor = (type: string) => {
126	    const option = evidenceTypeOptions.find((opt) => opt.value === type);
127	    return option ? option.color : 'bg-gray-50 text-gray-700';
128	  };
129	
130	  // Auto-save function with debouncing
131	  const autoSave = useCallback(
132	    debounce(async (content: any, metadata: Partial<EvidenceItem>) => {
133	      const saveTime = new Date().toLocaleTimeString();
134	      console.log(
135	        `[${saveTime}] 💾 NODE AUTO-SAVE: Starting auto-save process`
136	      );
137	
138	      if (!editorRef.current) {
139	        console.log(
140	          `[${saveTime}] ⚠️ NODE AUTO-SAVE: Editor not available, skipping`
141	        );
142	        return;
143	      }
144	
145	      try {
146	        setIsAutoSaving(true);
147	        console.log(`[${saveTime}] 🔄 NODE AUTO-SAVE: Validating content`);
148	
149	        const validatedContent = validateAndMigrateEditorData(content);
150	
151	        const updatedEvidence: EvidenceItem = {
152	          ...evidence,
153	          ...metadata,
154	          content: validatedContent,
155	          updatedAt: new Date().toISOString(),
156	        };
157	
158	        console.log(`[${saveTime}] 📤 NODE AUTO-SAVE: Saving to store`);
159	        onUpdateEvidence(evidence.id, updatedEvidence);
160	        setLastSaved(new Date());
161	
162	        console.log(`[${saveTime}] ✅ NODE AUTO-SAVE: Success`);
163	      } catch (error) {
164	        const errorTime = new Date().toLocaleTimeString();
165	        console.error(`[${errorTime}] ❌ NODE AUTO-SAVE ERROR:`, error);
166	        toast.error('Auto-save failed', {
167	          duration: 2000,
168	          position: 'bottom-right',
169	        });
170	      } finally {
171	        setIsAutoSaving(false);
172	      }
173	    }, 3000),
174	    [evidence, onUpdateEvidence]
175	  );
176	
177	  // Handle editor changes for auto-save
178	  const handleEditorChange = useCallback(async () => {
179	    const changeTime = new Date().toLocaleTimeString();
180	    console.log(`[${changeTime}] ⚡ NODE CHANGE: Editor content changed`);
181	
182	    if (!editorRef.current) {
183	      console.log(`[${changeTime}] ⚠️ NODE CHANGE: Editor not available`);
184	      return;
185	    }
186	
187	    try {
188	      setTimeout(async () => {
189	        try {
190	          const content = await editorRef.current!.save();
191	          console.log(
192	            `[${new Date().toLocaleTimeString()}] 📝 NODE CHANGE: Content saved, triggering auto-save`
193	          );
194	          autoSave(content, editForm);
195	        } catch (error) {
196	          console.error(
197	            `[${new Date().toLocaleTimeString()}] ❌ NODE CHANGE ERROR:`,
198	            error
199	          );
200	        }
201	      }, 100);
202	    } catch (error) {
203	      console.error(`[${changeTime}] ❌ NODE CHANGE ERROR:`, error);
204	    }
205	  }, [autoSave, editForm]);
206	
207	  const handleToggleExpanded = () => {
208	    const newExpanded = !isExpanded;
209	    setIsExpanded(newExpanded);
210	    onUpdateEvidence(evidence.id, { isExpanded: newExpanded });
211	  };
212	
213	  const handleSaveEdit = async () => {
214	    if (!editorRef.current) return;
215	
216	    setIsLoading(true);
217	    try {
218	      const outputData = await editorRef.current.save();
219	      const validatedContent = validateAndMigrateEditorData(outputData);
220	
221	      const updatedEvidence: EvidenceItem = {
222	        ...evidence,
223	        ...editForm,
224	        content: validatedContent,
225	        updatedAt: new Date().toISOString(),
226	      };
227	
228	      onUpdateEvidence(evidence.id, updatedEvidence);
229	      setLastSaved(new Date());
230	      setIsEditing(false);
231	      toast.success('Evidence saved successfully!');
232	    } catch (error) {
233	      console.error('Error saving evidence:', error);
234	      toast.error('Failed to save evidence');
235	    } finally {
236	      setIsLoading(false);
237	    }
238	  };
239	
240	  // Initialize Editor.js when editing starts
241	  useEffect(() => {
242	    if (isEditing && editorContainerRef.current && !editorRef.current) {
243	      const container = editorContainerRef.current;
244	      if (!container) {
245	        console.warn('Editor container not found');
246	        return;
247	      }
248	
249	      try {
250	        const initTime = new Date().toLocaleTimeString();
251	        console.log(
252	          `[${initTime}] 🚀 NODE INIT: Starting EditorJS initialization`
253	        );
254	
255	        const editor = createEditorJSInstance({
256	          holder: container,
257	          data: evidence?.content,
258	          placeholder:
259	            "Start writing your evidence notebook... Press '/' for commands",
