261	          onChange: handleEditorChange,
262	          onReady: () => {
263	            const readyTime = new Date().toLocaleTimeString();
264	            console.log(
265	              `[${readyTime}] 🎉 NODE INIT: Editor ready and operational`
266	            );
267	          },
268	          onError: (error) => {
269	            console.error('❌ NODE EditorJS error:', error);
270	            toast.error('Editor error occurred. Auto-saving is still active.', {
271	              duration: 3000,
272	              position: 'bottom-right',
273	            });
274	          },
275	        });
276	
277	        editorRef.current = editor;
278	      } catch (error) {
279	        console.error('❌ Failed to initialize stable EditorJS:', error);
280	        toast.error('Editor initialization failed.', {
281	          duration: 3000,
282	          position: 'bottom-right',
283	        });
284	      }
285	    }
286	
287	    return () => {
288	      if (editorRef.current && !isEditing) {
289	        try {
290	          editorRef.current.destroy();
291	          editorRef.current = null;
292	        } catch (error) {
293	          console.warn('Error destroying editor:', error);
