                      }
                      placeholder="Evidence title"
                      className="nodrag text-lg font-bold border-none p-0 focus:ring-0"
                    />
                    <div className="flex items-center gap-4 text-sm text-gray-500">
                      <div className="flex items-center gap-2">
                        <User className="h-4 w-4" />
                        <Input
                          value={editForm.owner}
                          onChange={(e) =>
                            setEditForm({ ...editForm, owner: e.target.value })
                          }
                          placeholder="Owner"
                          className="nodrag border-none p-0 text-sm focus:ring-0"
                        />
                      </div>
                      <div className="flex items-center gap-2">
                        <Calendar className="h-4 w-4" />
                        <Input
                          type="date"
                          value={editForm.date}
                          onChange={(e) =>
                            setEditForm({ ...editForm, date: e.target.value })
                          }
                          className="nodrag border-none p-0 text-sm focus:ring-0"
                        />
                      </div>
                    </div>
                  </div>
                ) : (
                  <>
                    <CardTitle className="text-lg font-semibold">
                      {evidence.title}
                    </CardTitle>
                    <div className="flex items-center gap-2 text-xs text-gray-500 mt-1">
                      <Badge variant="secondary" className="text-xs">
                        {evidence.type}
                      </Badge>
                      <div className="flex items-center gap-1">
                        <Calendar className="h-3 w-3" />
                        {new Date(evidence.date).toLocaleDateString()}
                      </div>
                    </div>
                  </>
                )}
              </div>
            </div>
            <div className="nodrag flex items-center gap-1">
              {isEditing && (
                <>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setIsFullscreen(!isFullscreen)}
                    title={
                      isFullscreen ? 'Exit fullscreen' : 'Enter fullscreen'
                    }
                    className="nodrag"
                  >
                    {isFullscreen ? (
                      <Minimize2 className="h-3 w-3" />
                    ) : (
                      <Maximize2 className="h-3 w-3" />
                    )}
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={handleSaveEdit}
                    disabled={isLoading}
                    className="nodrag"
                  >
                    <Save className="h-3 w-3 mr-1" />
                    {isLoading ? 'Saving...' : 'Save'}
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setIsEditing(false)}
                    className="nodrag"
                  >
                    <X className="h-3 w-3" />
                  </Button>
                </>
              )}
              <Button
                variant="ghost"
                size="sm"
                onClick={handleToggleExpanded}
                className="nodrag h-6 w-6 p-0"
              >
                <ChevronUp className="h-3 w-3" />
              </Button>
              {!isEditing && (
                <>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setIsEditing(true)}
                    className="nodrag h-6 w-6 p-0"
                  >
                    <Edit className="h-3 w-3" />
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={handleDeleteEvidence}
                    className="nodrag h-6 w-6 p-0 text-red-500 hover:text-red-700"
                  >
                    <Trash2 className="h-3 w-3" />
                  </Button>
                  <Link
                    to={`/evidence/${evidence.id}`}
                    title="Open full page"
                    className="nodrag"
                  >
                    <Button
                      variant="ghost"
                      size="sm"
                      className="nodrag h-6 w-6 p-0"
                    >
                      <ExternalLink className="h-3 w-3" />
                    </Button>
                  </Link>
                </>
              )}
            </div>
          </div>
        </CardHeader>

        {/* Auto-save indicator */}
        {(isAutoSaving || lastSaved) && isEditing && (
          <div className="px-6 py-2 bg-blue-50 border-b border-blue-200">
            <div className="flex items-center gap-2 text-sm text-blue-700">
              {isAutoSaving ? (
                <>
                  <div className="w-2 h-2 bg-blue-500 rounded-full animate-pulse"></div>
                  <span>Auto-saving...</span>
                </>
              ) : (
                <>
                  <div className="w-2 h-2 bg-green-500 rounded-full"></div>
                  <span>Last saved: {lastSaved?.toLocaleTimeString()}</span>
                </>
              )}
            </div>
          </div>
        )}

        {/* Metadata Section */}
        {isEditing && (
          <div className="nodrag px-6 py-4 border-b bg-gray-50">
            <div
              className={`grid gap-4 ${isFullscreen ? 'grid-cols-1 md:grid-cols-6' : 'grid-cols-1 md:grid-cols-3'}`}
            >
              <div>
                <Label className="text-xs font-medium text-gray-600">
                  Hypothesis
                </Label>
                <Input
                  value={editForm.hypothesis}
                  onChange={(e) =>
                    setEditForm({ ...editForm, hypothesis: e.target.value })
                  }
                  placeholder="What hypothesis is being tested?"
                  className="nodrag mt-1"
                />
              </div>
              <div>
                <Label className="text-xs font-medium text-gray-600">
                  External Link
                </Label>
                <Input
                  value={editForm.link}
                  onChange={(e) =>
                    setEditForm({ ...editForm, link: e.target.value })
                  }
                  placeholder="https://..."
                  className="nodrag mt-1"
                />
              </div>
              <div>
                <Label className="text-xs font-medium text-gray-600">
                  Impact on Confidence
                </Label>
                <Input
                  value={editForm.impactOnConfidence}
                  onChange={(e) =>
                    setEditForm({
                      ...editForm,
                      impactOnConfidence: e.target.value,
                    })
                  }
                  placeholder="How does this affect confidence?"
                  className="nodrag mt-1"
                />
              </div>
              <div className="md:col-span-3">
                <Label className="text-xs font-medium text-gray-600">
                  Tags
                </Label>
                <EnhancedTagInput
                  tags={editForm.tags || []}
                  onAdd={(tag) =>
                    setEditForm({
                      ...editForm,
                      tags: [...(editForm.tags || []), tag],
                    })
                  }
                  onRemove={(tag) =>
                    setEditForm({
                      ...editForm,
                      tags: (editForm.tags || []).filter((t) => t !== tag),
                    })
                  }
                  className="nodrag mt-1"
                />
              </div>
            </div>
          </div>
        )}

        <CardContent className="space-y-3">
          {/* Content */}
          <div>
            <div className="flex items-center justify-between">
              <span className="text-xs font-medium text-gray-500 uppercase tracking-wide">
                CONTENT
              </span>
              {!isEditing && (
                <Link
                  to={`/evidence/${evidence.id}`}
                  className="nodrag text-xs text-blue-600 hover:text-blue-800 hover:underline"
                  title="View full content"
                >
                  View Full
                </Link>
              )}
            </div>
            <div className="mt-2">
              {isEditing ? (
                <div
                  ref={editorContainerRef}
                  className="nodrag codex-editor"
                  style={{ minHeight: '300px' }}
                />
              ) : (
                <div className="max-h-32 overflow-hidden relative">
