                  <div className="absolute bottom-0 left-0 right-0 h-8 bg-gradient-to-t from-white to-transparent pointer-events-none" />
                </div>
              )}
            </div>
          </div>

          {/* Link */}
          {evidence.link && !isEditing && (
            <div className="pt-2">
              <a
                href={evidence.link}
                target="_blank"
                rel="noopener noreferrer"
                className="inline-flex items-center gap-1 text-sm text-blue-600 hover:text-blue-800 hover:underline"
              >
                <ExternalLink className="h-3 w-3" />
                View Source
              </a>
            </div>
          )}

          {/* Comments */}
          <div className="nodrag border-t pt-3">
            <div className="flex items-center justify-between mb-2">
              <span className="text-xs font-medium text-gray-500 uppercase tracking-wide">
                COMMENTS ({evidence.comments?.length || 0})
              </span>
            </div>

            {evidence.comments && evidence.comments.length > 0 && (
              <div className="space-y-2 max-h-40 overflow-y-auto pr-1">
                {evidence.comments.map((comment: EvidenceComment) => (
                  <div
                    key={comment.id}
                    className="text-xs bg-gray-50 p-2 rounded border"
                  >
                    <div className="flex items-center gap-1 mb-1">
                      <User className="h-3 w-3" />
                      <span className="font-medium">{comment.author}</span>
                      <span className="text-gray-400">
                        {new Date(comment.createdAt).toLocaleDateString()}
                      </span>
                    </div>
                    <p className="text-gray-700">{comment.content}</p>
                  </div>
                ))}
              </div>
            )}
            <div className="mt-2 flex gap-2">
              <Input
                value={newComment}
                onChange={(e) => setNewComment(e.target.value)}
                placeholder="Add a comment..."
                className="nodrag"
              />
              <Button
                variant="outline"
                disabled={!newComment.trim()}
                onClick={() => {
                  if (!newComment.trim()) return;
                  addComment(evidence.id, {
                    content: newComment,
                    author: 'Current User',
                  });
                  setNewComment('');
                }}
                className="nodrag text-xs"
              >
                Add
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Add Comment Dialog */}
      <Dialog open={isCommentDialogOpen} onOpenChange={setIsCommentDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Add Comment</DialogTitle>
            <DialogDescription>
