            />
          </div>
          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => setIsCommentDialogOpen(false)}
            >
              Cancel
            </Button>
            <Button onClick={handleAddComment}>Add Comment</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

export const convertToEvidenceNode = (
  evidence: EvidenceItem,
  onUpdateEvidence: (id: string, updates: Partial<EvidenceItem>) => void,
  onDeleteEvidence: (id: string) => void
): Node => ({
  id: evidence.id,
  type: 'evidenceNode',
  position: evidence.position || { x: 100, y: 100 },
  data: {
    evidence,
    onUpdateEvidence,
    onDeleteEvidence,
  },
  dragHandle: '.evidence-drag-handle',
});

// Convert GroupNode to ReactFlow Node
export const convertToGroupNode = (
  group: GroupNodeType,
  onEditGroup: (groupId: string) => void,
  onDeleteGroup: (groupId: string) => void,
  onToggleCollapse: (groupId: string) => void,
  onResizeGroup: (
    groupId: string,
    size: { width: number; height: number }
  ) => void,
  onColorChange?: (groupId: string, color: string) => void
): Node => ({
  id: group.id,
  position: group.position,
  data: {
    group,
    onEditGroup,
    onDeleteGroup,
    onToggleCollapse,
    onResizeGroup,
    onColorChange,
  },
  type: 'groupNode',
  style: {
    width: group.size.width,
    height: group.isCollapsed ? 60 : group.size.height,
  },
  draggable: true,
  selectable: true,
  // Drag the frame only from its header bar (Figma-style); the body sits behind
  // the cards (zIndex 0 + ordered first) so the cards stay interactive.
  dragHandle: '.group-drag-handle',
  zIndex: 0,
  className: 'group-node',
});

// Import additional node components
import { WhiteboardNode } from '@/features/canvas/components/nodes';
import CommentNode from '@/features/canvas/components/nodes/comment-node';
import type { CanvasNode } from '@/shared/types';

// Convert CanvasNode to ReactFlow Node
export const convertToCanvasNode = (
  canvasNode: CanvasNode,
  selectedNodeIds: string[] = []
): Node => ({
  id: canvasNode.id,
  type: canvasNode.nodeType,
  position: canvasNode.position,
  data: {
    ...canvasNode.data,
    title: canvasNode.title,
    projectId: canvasNode.projectId,
    // Ensure all node types have the required data structure
    ...(canvasNode.nodeType === 'commentNode' && {
      title: canvasNode.title || 'Comment',
    }),
    // Operator: normalize legacy data (boolean→toggle, datePicker→passthrough)
    // and the new shape (named inputs, per-type config) at read time.
    ...(canvasNode.nodeType === 'operatorNode' &&
      normalizeOperatorData(canvasNode.data as any)),
    ...(canvasNode.nodeType === 'sourceNode' && {
      title: canvasNode.title || 'Source',
      sourceType: canvasNode.data?.sourceType || 'warehouse',
    }),
    ...(canvasNode.nodeType === 'chartNode' && {
      title: canvasNode.title || 'Chart',
    }),
    ...(canvasNode.nodeType === 'whiteboardNode' && {
      shape: canvasNode.data?.shape || 'rect',
    }),
  },
  selected: selectedNodeIds.includes(canvasNode.id),
  selectable: true,
  draggable: true,
});

// Define custom node and edge types for ReactFlow
export const nodeTypes = {
  // Legacy node types (for backward compatibility)
  metricCard: MetricCard,
  groupNode: GroupNode,
  evidenceNode: EvidenceNode,
  sourceNode: SourceNode,
  chartNode: ChartNode,
  operatorNode: OperatorNode,
  whiteboardNode: WhiteboardNode,
  commentNode: CommentNode,

  // New PRD-based node types
  valueNode: ValueNode,
  actionNode: ActionNode,
  hypothesisNode: HypothesisNode,
  metricNode: MetricNode,
};

export const edgeTypes = {
  dynamicEdge: DynamicEdge, // Relationship Edge - Business logic connections
  operativeEdge: OperativeEdge, // Data Flow Edge - Data pipeline connections
  dataFlowEdge: DataFlowEdge, // Alternative Data Flow Edge component
  referenceEdge: ReferenceEdge, // Reference Edge - Simple reference connections
};

    stableEvents.handleSwitchToCard,
    state.isSettingsSheetOpen,
    selectedNodeIds
  )
);

// Convert persisted canvas nodes to ReactFlow nodes
const convertedPersistedCanvasNodes = persistedCanvasNodes.map(
  (canvasNode) => convertToCanvasNode(canvasNode, selectedNodeIds)
);

// Convert new node types to ReactFlow nodes
const convertedNewNodeTypes = newNodeTypes.map((node) => ({
  id: node.id,
  type: node.type,
  position: node.position,
  data: { node },
  selected: selectedNodeIds.includes(node.id),
  selectable: true,
  draggable: true,
}));

const convertedEvidenceNodes = evidenceNodes.map((evidence) =>
  convertToEvidenceNode(
    evidence,
    () => console.log('Update evidence:', evidence.id),
    () => console.log('Delete evidence:', evidence.id)
  )
);

// Grouping redesign: the on-canvas group frame is gone. Group data still
// lives in canvas.groups (used by the Groups side panel + dashboard scope);
// it just no longer renders as a rectangle node here.
const allNodes = [
  ...convertedMetricCardNodes,
  ...convertedEvidenceNodes,
  ...convertedPersistedCanvasNodes,
  ...convertedNewNodeTypes,
  // Only include temporary nodes if they exist (for immediate UI feedback)
  ...(temporaryExtraNodes.length > 0 ? temporaryExtraNodes : []),
];

// Focus mode: dim every node that isn't a member of the focused group to
// faint context (members stay bright). Edges are dimmed in the edges memo.
if (focusedGroupId) {
  const fg = (canvas?.groups || []).find((g) => g.id === focusedGroupId);
  const members = new Set(fg?.nodeIds || []);
  return allNodes.map((n) =>
    members.has(n.id)
      ? n
      : {
          ...n,
          className: [(n as any).className, 'rf-node-dimmed']
            .filter(Boolean)
            .join(' '),
        }
  );
}

return allNodes;

