        ...(temporaryExtraNodes || []),
        fallbackNode as any,
      ]);

      // Clear temporary node after a short delay to avoid conflicts
      setTimeout(() => {
        state.setExtraNodes([]);
      }, 5000); // Increased timeout to give more time for debugging
    }
  },
  [createCanvasNode, state]
);

